module top_module(
	input [7:0] obf_A, B,
	output reg [7:0] Out6
);always@(obf_A or B)
	begin
		Out6[0] <= ~(obf_A[0] & B[0]);
		Out6[1] <= ~(obf_A[1] & B[1]);
		Out6[2] <= ~(obf_A[2] & B[2]);
		Out6[3] <= ~(obf_A[3] & B[3]);
		Out6[4] <= ~(obf_A[4] & B[4]);
		Out6[5] <= ~(obf_A[5] & B[5]);
		Out6[6] <= ~(obf_A[6] & B[6]);
		Out6[7] <= ~(obf_A[7] & B[7]);
	end

endmodule
